sql:
SELECT chemical_id, SUM(total_usage) AS overall_consumption_total
FROM chemical_years
GROUP BY chemical_id;

SELECT DISTINCT c.chemical_name, c.cas_number
FROM chemicals c
INNER JOIN survey_results sr ON c.chemical_id = sr.chemical_id;

SELECT *
FROM chemical_usage
WHERE survey_id = 0;

SELECT chemical_id, chemical_name
FROM chemicals
WHERE chemical_type = 'herbicide';

external_knowledge:
- 'past decade' refers to the years between 2010 and 2020;
- 'typical amount of land they covered' refers to the average total acres treated;
- 'average quantity applied' refers to the average total amount of chemical applied.
